import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.web.bind.annotation.*;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.security.cert.X509Certificate;
import java.util.Base64;
import java.time.Instant;
import java.util.HashMap;
import java.util.Map;

@SpringBootApplication
@EnableWebSecurity
public class BiometricSecurityApplication {

    public static void main(String[] args) {
        SpringApplication.run(BiometricSecurityApplication.class, args);
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .requiresChannel(channel -> channel
                .anyRequest().requiresSecure() // Enforce HTTPS only
            )
            .csrf().disable() // Use custom HMAC-based protection instead
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/api/biometric/**").authenticated()
                .anyRequest().permitAll()
            );
        return http.build();
    }
}

@RestController
@RequestMapping("/api/biometric")
class BiometricAuthController {

    private static final String SENSOR_SHARED_SECRET = System.getenv("BIOMETRIC_SENSOR_SECRET");
    private static final long MAX_TIMESTAMP_DRIFT_MS = 5000; // 5 seconds

    /**
     * Accepts biometric data ONLY from authenticated hardware sensors.
     * Prevents injection attacks via virtual cameras or man-in-the-middle.
     */
    @PostMapping("/authenticate")
    public ResponseEntity<?> authenticateBiometric(
            @RequestHeader("X-Sensor-Certificate") String sensorCertBase64,
            @RequestHeader("X-Sensor-Signature") String sensorSignature,
            @RequestHeader("X-Timestamp") long timestamp,
            @RequestHeader("X-Nonce") String nonce,
            @RequestBody BiometricAuthRequest request) {

        try {
            // Step 1: Verify sensor certificate (prevents rogue sensors)
            X509Certificate sensorCert = verifySensorCertificate(sensorCertBase64);
            if (sensorCert == null) {
                return ResponseEntity.status(403)
                    .body(Map.of("error", "Invalid sensor certificate",
                                 "code", "UNTRUSTED_SENSOR"));
            }

            // Step 2: Verify timestamp freshness (prevents replay attacks)
            long currentTime = Instant.now().toEpochMilli();
            if (Math.abs(currentTime - timestamp) > MAX_TIMESTAMP_DRIFT_MS) {
                return ResponseEntity.status(403)
                    .body(Map.of("error", "Timestamp outside acceptable range",
                                 "code", "REPLAY_ATTACK_SUSPECTED"));
            }

            // Step 3: Verify HMAC signature (ensures data integrity)
            String expectedSignature = generateHMAC(
                request.getBiometricData() + "|" + timestamp + "|" + nonce,
                SENSOR_SHARED_SECRET
            );

            if (!constantTimeEquals(sensorSignature, expectedSignature)) {
                logSecurityEvent("SIGNATURE_MISMATCH", request.getUserId(), 
                    request.headers.get("X-Forwarded-For"));
                return ResponseEntity.status(403)
                    .body(Map.of("error", "Signature verification failed",
                                 "code", "INJECTION_ATTACK_DETECTED"));
            }

            // Step 4: Verify sensor attestation (proves sensor is genuine hardware)
            boolean isGenuineSensor = verifyHardwareAttestation(
                sensorCert, 
                request.getAttestationToken()
            );

            if (!isGenuineSensor) {
                logSecurityEvent("VIRTUAL_SENSOR_DETECTED", request.getUserId(),
                    request.headers.get("X-Forwarded-For"));
                return ResponseEntity.status(403)
                    .body(Map.of("error", "Virtual sensor detected",
                                 "code", "HARDWARE_ATTESTATION_FAILED"));
            }

            // Step 5: Validate biometric data stream integrity
            // Check for signs of synthetic/manipulated data
            BiometricQualityMetrics metrics = analyzeBiometricQuality(
                request.getBiometricData()
            );

            if (metrics.isSynthetic || metrics.qualityScore < 0.6) {
                logSecurityEvent("SYNTHETIC_BIOMETRIC_DETECTED", 
                    request.getUserId(),
                    Map.of(
                        "qualityScore", metrics.qualityScore,
                        "syntheticProbability", metrics.syntheticProbability
                    )
                );
                return ResponseEntity.status(403)
                    .body(Map.of("error", "Biometric quality too low or synthetic data detected",
                                 "code", "SYNTHETIC_BIOMETRIC"));
            }

            // Step 6: Perform actual biometric matching
            BiometricMatchResult matchResult = performBiometricMatch(
                request.getUserId(),
                request.getBiometricData()
            );

            if (matchResult.isMatch && matchResult.confidenceScore > 0.85) {
                String authToken = generateSecureAuthToken(request.getUserId());
                return ResponseEntity.ok(Map.of(
                    "authenticated", true,
                    "authToken", authToken,
                    "expiresIn", 3600,
                    "matchScore", matchResult.confidenceScore
                ));
            } else {
                return ResponseEntity.status(401)
                    .body(Map.of("authenticated", false,
                                 "reason", "Biometric mismatch"));
            }

        } catch (Exception e) {
            log.error("Biometric authentication error", e);
            return ResponseEntity.status(500)
                .body(Map.of("error", "Internal authentication error"));
        }
    }

    /**
     * Verifies sensor certificate against trusted CA.
     * Implements certificate pinning to prevent MITM attacks.
     */
    private X509Certificate verifySensorCertificate(String certBase64) {
        try {
            byte[] certBytes = Base64.getDecoder().decode(certBase64);
            CertificateFactory cf = CertificateFactory.getInstance("X.509");
            X509Certificate cert = (X509Certificate) cf.generateCertificate(
                new ByteArrayInputStream(certBytes)
            );

            // Verify certificate chain
            cert.checkValidity(); // Check expiration

            // Pin to specific trusted CA public key
            String trustedCAPublicKey = System.getenv("TRUSTED_SENSOR_CA_PUBLIC_KEY");
            String certPublicKey = Base64.getEncoder().encodeToString(
                cert.getPublicKey().getEncoded()
            );

            // Verify certificate was issued by trusted CA
            if (!verifyCertificateChain(cert, trustedCAPublicKey)) {
                return null;
            }

            return cert;
        } catch (Exception e) {
            log.error("Certificate verification failed", e);
            return null;
        }
    }

    /**
     * Verifies hardware attestation to ensure biometric sensor is genuine.
     * Prevents virtual camera/sensor injection attacks.
     */
    private boolean verifyHardwareAttestation(
            X509Certificate sensorCert, 
            String attestationToken) {

        // Implement platform-specific attestation verification
        // - Android: SafetyNet / Play Integrity API
        // - iOS: DeviceCheck / App Attest
        // - Windows: TPM-based attestation
        // - Hardware sensors: Manufacturer-specific attestation

        try {
            // Decode attestation token (JWT format)
            String[] parts = attestationToken.split("\\.");
            String payload = new String(Base64.getUrlDecoder().decode(parts[1]));
            JSONObject attestation = new JSONObject(payload);

            // Verify attestation signature using sensor's public key
            boolean signatureValid = verifyJWTSignature(
                attestationToken, 
                sensorCert.getPublicKey()
            );

            if (!signatureValid) {
                return false;
            }

            // Check attestation claims
            boolean isHardwareBacked = attestation.getBoolean("hardwareBacked");
            String deviceIntegrity = attestation.getString("deviceIntegrity");

            // MEETS_DEVICE_INTEGRITY = genuine device
            // MEETS_BASIC_INTEGRITY = potentially rooted/emulated
            return isHardwareBacked && "MEETS_DEVICE_INTEGRITY".equals(deviceIntegrity);

        } catch (Exception e) {
            log.error("Hardware attestation verification failed", e);
            return false;
        }
    }

    /**
     * Analyzes biometric data for signs of synthetic/manipulated content.
     */
    private BiometricQualityMetrics analyzeBiometricQuality(String biometricData) {
        // Implement AI-based synthetic biometric detection
        // Check for:
        // - Compression artifacts (deepfake indicators)
        // - Unnatural frequency distributions
        // - Pixel-level inconsistencies
        // - Motion blur patterns inconsistent with real capture

        BiometricQualityMetrics metrics = new BiometricQualityMetrics();
        metrics.qualityScore = 0.85; // Placeholder
        metrics.syntheticProbability = 0.05;
        metrics.isSynthetic = metrics.syntheticProbability > 0.5;

        return metrics;
    }

    /**
     * Constant-time string comparison to prevent timing attacks.
     */
    private boolean constantTimeEquals(String a, String b) {
        if (a.length() != b.length()) {
            return false;
        }

        int result = 0;
        for (int i = 0; i < a.length(); i++) {
            result |= a.charAt(i) ^ b.charAt(i);
        }
        return result == 0;
    }

    /**
     * Generates HMAC-SHA256 signature for data integrity.
     */
    private String generateHMAC(String data, String secret) throws Exception {
        Mac hmac = Mac.getInstance("HmacSHA256");
        SecretKeySpec secretKey = new SecretKeySpec(secret.getBytes(), "HmacSHA256");
        hmac.init(secretKey);
        byte[] signature = hmac.doFinal(data.getBytes());
        return Base64.getEncoder().encodeToString(signature);
    }
}

