const express = require('express');
const BioCatch = require('biocatch-sdk'); // Behavioral biometrics SDK
const geoip = require('geoip-lite');
const DeviceDetector = require('device-detector-js');

const app = express();
app.use(express.json());

// Initialize BioCatch for behavioral biometrics
const bioCatch = new BioCatch({
  customerSessionId: process.env.BIOCATCH_SESSION_ID,
  customerId: process.env.BIOCATCH_CUSTOMER_ID,
  features: {
    mouseTracking: true,
    keystrokeDynamics: true,
    touchPressure: true,
    deviceOrientation: true,
    focusEvents: true
  }
});

// Risk scoring thresholds
const RISK_THRESHOLDS = {
  LOW: 30,
  MEDIUM: 60,
  HIGH: 80,
  CRITICAL: 95
};

/**
 * Middleware: Continuous authentication with risk assessment
 */
app.use('/api/*', async (req, res, next) => {
  try {
    // Calculate risk score based on multiple factors
    const riskScore = await calculateRiskScore(req);

    req.riskScore = riskScore.total;
    req.riskFactors = riskScore.factors;

    // Log for SIEM analysis
    console.log(JSON.stringify({
      eventType: 'RISK_ASSESSMENT',
      userId: req.user?.id,
      riskScore: riskScore.total,
      factors: riskScore.factors,
      endpoint: req.path,
      timestamp: new Date().toISOString()
    }));

    next();
  } catch (error) {
    console.error('Risk assessment failed:', error);
    res.status(500).json({ error: 'Security check failed' });
  }
});

/**
 * Calculate comprehensive risk score
 */
async function calculateRiskScore(req) {
  const factors = {};
  let totalScore = 0;

  // Factor 1: Behavioral biometrics (40% weight)
  const behaviorScore = await analyzeBehavioralBiometrics(req);
  factors.behavioral = {
    score: behaviorScore,
    weight: 0.40,
    contribution: behaviorScore * 0.40
  };
  totalScore += factors.behavioral.contribution;

  // Factor 2: Device fingerprint (20% weight)
  const deviceScore = await analyzeDeviceFingerprint(req);
  factors.device = {
    score: deviceScore,
    weight: 0.20,
    contribution: deviceScore * 0.20
  };
  totalScore += factors.device.contribution;

  // Factor 3: Geolocation anomaly (15% weight)
  const geoScore = await analyzeGeolocation(req);
  factors.geolocation = {
    score: geoScore,
    weight: 0.15,
    contribution: geoScore * 0.15
  };
  totalScore += factors.geolocation.contribution;

  // Factor 4: Velocity checks (15% weight)
  const velocityScore = await analyzeVelocity(req);
  factors.velocity = {
    score: velocityScore,
    weight: 0.15,
    contribution: velocityScore * 0.15
  };
  totalScore += factors.velocity.contribution;

  // Factor 5: Threat intelligence (10% weight)
  const threatScore = await checkThreatIntelligence(req);
  factors.threatIntel = {
    score: threatScore,
    weight: 0.10,
    contribution: threatScore * 0.10
  };
  totalScore += factors.threatIntel.contribution;

  return {
    total: Math.round(totalScore),
    factors: factors,
    level: getRiskLevel(totalScore)
  };
}

/**
 * Analyze behavioral biometrics (typing, mouse, touch patterns)
 */
async function analyzeBehavioralBiometrics(req) {
  const userId = req.user?.id;
  const behavioralData = req.body.behavioralData || {};

  try {
    // Submit behavioral data to BioCatch for analysis
    const result = await bioCatch.analyze({
      userId: userId,
      sessionId: req.sessionID,
      mouseMovements: behavioralData.mouseMovements,
      keystrokeDynamics: behavioralData.keystrokes,
      touchPressure: behavioralData.touchEvents,
      scrollPatterns: behavioralData.scrolling
    });

    // BioCatch returns risk score 0-100 (100 = highest risk)
    // Higher score = more anomalous behavior = higher risk
    const anomalyScore = result.riskScore;

    // Check for specific red flags
    const redFlags = [];

    if (result.flags.roboticMouseMovement) {
      redFlags.push('Robotic mouse movement detected (bot suspected)');
    }

    if (result.flags.copyPastePassword) {
      redFlags.push('Password manager detected (credential stuffing risk)');
    }

    if (result.flags.unusualTypingSpeed) {
      redFlags.push('Typing speed anomaly (different user or automation)');
    }

    if (redFlags.length > 0) {
      await logSecurityEvent({
        type: 'BEHAVIORAL_ANOMALY',
        userId: userId,
        redFlags: redFlags,
        anomalyScore: anomalyScore
      });
    }

    return anomalyScore;

  } catch (error) {
    console.error('Behavioral analysis error:', error);
    return 50; // Default medium risk on error
  }
}

/**
 * Analyze device fingerprint changes
 */
async function analyzeDeviceFingerprint(req) {
  const userId = req.user?.id;
  const currentFingerprint = generateDeviceFingerprint(req);

  // Retrieve known device fingerprints for user
  const knownDevices = await getKnownDevices(userId);

  if (knownDevices.includes(currentFingerprint)) {
    return 0; // Known device, low risk
  }

  // New device detected
  const deviceDetector = new DeviceDetector();
  const device = deviceDetector.parse(req.headers['user-agent']);

  // Higher risk for:
  // - Bots/crawlers
  // - Emulators
  // - Suspicious user agents
  if (device.bot || device.client?.name === 'Emulator') {
    return 90; // Very high risk
  }

  return 60; // Medium-high risk for new device
}

/**
 * Analyze geolocation anomalies
 */
async function analyzeGeolocation(req) {
  const userId = req.user?.id;
  const ip = req.ip || req.connection.remoteAddress;
  const geo = geoip.lookup(ip);

  if (!geo) {
    return 70; // Unable to determine location = risk
  }

  // Get user's typical locations
  const userLocations = await getUserLocationHistory(userId);

  // Check for impossible travel
  const lastLogin = userLocations[0];
  if (lastLogin) {
    const distance = calculateDistance(
      lastLogin.latitude, lastLogin.longitude,
      geo.ll[0], geo.ll[1]
    );

    const timeDiff = (Date.now() - lastLogin.timestamp) / 1000 / 3600; // hours
    const maxPossibleSpeed = 900; // km/h (jet airplane)
    const requiredSpeed = distance / timeDiff;

    if (requiredSpeed > maxPossibleSpeed) {
      // Impossible travel detected
      await logSecurityEvent({
        type: 'IMPOSSIBLE_TRAVEL',
        userId: userId,
        fromLocation: `${lastLogin.city}, ${lastLogin.country}`,
        toLocation: `${geo.city}, ${geo.country}`,
        distance: distance,
        timeDiff: timeDiff,
        requiredSpeed: requiredSpeed
      });

      return 95; // Critical risk
    }
  }

  // Check if country is unusual for user
  const commonCountries = userLocations.map(l => l.country);
  const countryFrequency = commonCountries.filter(c => c === geo.country).length;

  if (countryFrequency === 0) {
    return 50; // New country = medium risk
  }

  return 10; // Typical location = low risk
}

/**
 * Analyze velocity (rate limiting)
 */
async function analyzeVelocity(req) {
  const userId = req.user?.id;
  const ip = req.ip;

  // Check request velocity (requests per minute)
  const userRequestCount = await getRequestCount(userId, 60); // last 60 seconds
  const ipRequestCount = await getRequestCount(ip, 60);

  // Thresholds
  if (userRequestCount > 100 || ipRequestCount > 100) {
    return 90; // Potential bot/script
  }

  if (userRequestCount > 50 || ipRequestCount > 50) {
    return 60; // Unusual activity
  }

  // Check failed authentication attempts
  const failedAttempts = await getFailedAuthAttempts(userId, 600); // last 10 minutes

  if (failedAttempts > 5) {
    return 80; // Potential brute force
  }

  return 10; // Normal velocity
}

