 * Protected endpoint with risk-based step-up authentication
 */
app.post('/api/transfer-money', async (req, res) => {
  const { amount, toAccount } = req.body;
  const userId = req.user.id;

  // Determine required authentication level based on risk
  let requiredAuthLevel = 'biometric'; // default

  if (req.riskScore >= RISK_THRESHOLDS.HIGH || amount > 10000) {
    requiredAuthLevel = 'biometric+otp'; // step-up required
  }

  if (req.riskScore >= RISK_THRESHOLDS.CRITICAL || amount > 50000) {
    requiredAuthLevel = 'biometric+otp+video_call'; // maximum security
  }

  // Check if user has satisfied required auth level
  const currentAuthLevel = req.session.authLevel;

  if (currentAuthLevel !== requiredAuthLevel) {
    return res.status(403).json({
      error: 'Additional authentication required',
      code: 'STEP_UP_REQUIRED',
      requiredLevel: requiredAuthLevel,
      currentLevel: currentAuthLevel,
      riskScore: req.riskScore,
      reason: getRiskReason(req.riskFactors)
    });
  }

  // Proceed with transaction
  // ...

  res.json({ success: true, transactionId: '...' });
});

function getRiskLevel(score) {
  if (score >= RISK_THRESHOLDS.CRITICAL) return 'CRITICAL';
  if (score >= RISK_THRESHOLDS.HIGH) return 'HIGH';
  if (score >= RISK_THRESHOLDS.MEDIUM) return 'MEDIUM';
  return 'LOW';
}

function getRiskReason(factors) {
  const highRiskFactors = Object.entries(factors)
    .filter(([_, f]) => f.score > 70)
    .map(([name, _]) => name);

  return highRiskFactors.join(', ') || 'Multiple risk indicators';
}

